\begin{frame}
\frametitle{Limitations of Static Pruning}
\begin{itemize}
    \item Fixed pruning ratios completely ignore dynamic task stages.
    \item Aggressive pruning during fine manipulation causes critical spatial information loss.
    \item Action-aware dynamic mechanisms are essential for adaptive token reduction.
\end{itemize}
\end{frame}

\begin{frame}
\frametitle{Overview of Action-aware Dynamic Pruning (ADP)}
\begin{itemize}
    \item Features Action-aware Gating and Anticipatory Pruning mechanisms.
    \item Dynamically triggers pruning based on recent end-effector trajectories.
    \item Filters task-relevant visual features using text-to-vision cross-attention.
\end{itemize}
