\begin{frame}
\frametitle{Action-Aware Gating: Trajectory Distance Calculation}
\begin{itemize}
\item Compute cumulative arc-length distance in observation windows.
\item Sum Euclidean distances between consecutive position vectors.
\end{itemize}
\begin{equation*}
\delta_i=\sum_{t=b_i}^{e_i-1}\lVert \mathbf{p}_{t+1}-\mathbf{p}_t\rVert_2
\end{equation*}
\begin{itemize}
\item High distance denotes fast movement, enabling aggressive visual pruning.
\end{itemize}
\end{frame}

\begin{frame}
\frametitle{Action-Aware Gating: Dynamic Trigger Mechanism}
\begin{itemize}
\item Dual thresholds establish hysteresis, preventing unstable pruning state toggling.
\item Distance $\ge U^{(i)}$ triggers rough phase, enabling token pruning.
\item Distance $\le V^{(i)}$ triggers fine phase, retaining all visual tokens.
\end{itemize}
\begin{equation*}
s_{i+1} = \begin{cases} 1, & \delta_i \ge U^{(i)}, \\\\ 0, & \delta_i \le V^{(i)}, \\\\ s_i, & V^{(i)} < \delta_i < U^{(i)}. \end{cases}
\end{equation*}
\end{frame}

\begin{frame}
\frametitle{Synergy of Action-Awareness and Attention Pruning}
\begin{itemize}
    \item Action-aware gating allocates computational resources dynamically across task stages.
    \item Attention pruning provides semantic-aware visual feature compression when activated.
    \item Synergy ensures ultra-fast coarse inference and highly accurate fine control.
\end{itemize}
\end{frame}

